    sliceCompleteParams,
    async (args: Record<string, unknown>) => {
      const parsed = parseWorkflowArgs(sliceCompleteSchema, args);
      return handleSliceComplete(parsed.projectDir, parsed);
    },
  );

  server.tool(
    "gsd_complete_milestone",
