    keyFiles,
    keyDecisions,
    blockerDiscovered,
    verificationEvidence,
  } = args;
  const { executeTaskComplete } = await getWorkflowToolExecutors();
  return runSerializedWorkflowOperation(() =>
    executeTaskComplete(
      {
        taskId,
        sliceId,
        milestoneId,
        oneLiner,
        narrative,
        verification,
        deviations,
        knownIssues,
        keyFiles,
        keyDecisions,
        blockerDiscovered,
        verificationEvidence,
      },
      projectDir,
    ),
  );
}

