    validateMilestoneParams,
    async (args: Record<string, unknown>) => {
      const parsed = parseWorkflowArgs(validateMilestoneSchema, args);
      return handleValidateMilestone(parsed.projectDir, parsed);
    },
  );

  server.tool(
    "gsd_milestone_validate",
