const askQuestionOptionSchema = z.object({
  label: z.string().describe("User-facing label (1-5 words)"),
  description: z.string().describe("One short sentence explaining impact/tradeoff if selected"),
});

const askUserQuestionSchema = z.object({
  id: z.string().describe("Stable identifier for mapping answers (snake_case)"),
  header: z.string().describe("Short header label shown in the UI"),
  question: z.string().describe("Single-sentence prompt shown to the user"),
  options: z.array(askQuestionOptionSchema).describe("Concrete choices to present to the user"),
  allowMultiple: z.boolean().optional().describe("Allow selecting more than one option"),
});

type AskQuestion = z.infer<typeof askUserQuestionSchema>;

const askUserQuestionsParams = {
  questions: z.array(askUserQuestionSchema).describe("Questions to show the user. Prefer 1 and do not exceed 3."),
};
const askUserQuestionsSchema = z.object(askUserQuestionsParams);

const projectDirParam = z.string().describe("Absolute path to the project directory within the configured workflow root");

function textResult(text: string): McpToolResult {
  return { content: [{ type: "text", text }] };
}

function optionLabelsForQuestion(question: AskQuestion): string[] {
  const labels = question.options.map((option) => option.label);
  if (!question.allowMultiple && !labels.some((label) => /^(none of the above|other\b)/i.test(label.trim()))) {
    labels.push(OTHER_OPTION_LABEL);
  }
  return labels;
}

function describeQuestion(question: AskQuestion): string {
  const optionDetails = question.options
    .map((option) => `${option.label}: ${option.description}`)
    .join("\n");
  return `${question.question}${optionDetails ? `\n\nOptions:\n${optionDetails}` : ""}`;
}

function buildAskUserQuestionsMessage(questions: AskQuestion[]): string {
  return [
    "Please answer these GSD workflow questions.",
    ...questions.map((question, index) =>
      `${index + 1}. ${question.header}: ${question.question}`,
    ),
  ].join("\n");
}

function buildElicitationSchema(questions: AskQuestion[]): Record<string, unknown> {
  const properties: Record<string, unknown> = {};
  const required: string[] = [];

  for (const question of questions) {
    const labels = optionLabelsForQuestion(question);
    required.push(question.id);
    if (question.allowMultiple) {
      properties[question.id] = {
        type: "array",
        title: question.header,
        description: describeQuestion(question),
        items: { type: "string", enum: labels },
        default: [],
      };
    } else {
      properties[question.id] = {
        type: "string",
        title: question.header,
        description: describeQuestion(question),
        oneOf: labels.map((label) => ({ const: label, title: label })),
        default: labels[0],
      };
    }
    properties[`${question.id}${USER_NOTE_SUFFIX}`] = {
      type: "string",
      title: `${question.header} note`,
      description: "Optional free-form explanation or clarification for this answer.",
    };
  }

  return { type: "object", properties, required };
}

function formatElicitationAnswers(questions: AskQuestion[], content: Record<string, string | number | boolean | string[]>): string {
  const answers: Record<string, { answers: string[] }> = {};

  for (const question of questions) {
    const raw = content[question.id];
    const answerList = Array.isArray(raw)
      ? raw.map(String)
      : raw === undefined
        ? []
        : [String(raw)];
    const note = content[`${question.id}${USER_NOTE_SUFFIX}`];
    if (typeof note === "string" && note.trim().length > 0) {
      answerList.push(`user_note: ${note.trim()}`);
    }
    answers[question.id] = { answers: answerList };
  }

  return JSON.stringify({ answers });
}

async function handleAskUserQuestions(
  server: McpToolServer,
  args: Record<string, unknown>,
): Promise<McpToolResult> {
  const parsed = parseToolArgs(askUserQuestionsSchema, args);
  const { questions } = parsed;

  if (questions.length === 0 || questions.length > 3) {
    return textResult("Error: questions must contain 1-3 items");
  }

  const seenIds = new Set<string>();
  for (const question of questions) {
    if (seenIds.has(question.id)) {
      return textResult(`Error: duplicate question id \"${question.id}\"`);
    }
    seenIds.add(question.id);
    if (question.options.length === 0) {
      return textResult(`Error: ask_user_questions requires non-empty options for every question (question \"${question.id}\" has none)`);
    }
  }

  const underlyingServer = server.server;
  if (typeof underlyingServer?.elicitInput !== "function") {
    throw new Error("ask_user_questions requires an MCP server with form elicitation support.");
  }

  const result = await underlyingServer.elicitInput({
    mode: "form",
    message: buildAskUserQuestionsMessage(questions),
    requestedSchema: buildElicitationSchema(questions),
  });

  if (result.action !== "accept" || !result.content) {
    return textResult("ask_user_questions was cancelled before receiving a response");
  }

  return textResult(formatElicitationAnswers(questions, result.content));
}


