  const { projectDir: _projectDir, ...params } = args;
  return runSerializedWorkflowOperation(() => executeReplanSlice(params, projectDir));
}

async function handleCompleteMilestone(
  projectDir: string,
  args: z.infer<typeof completeMilestoneSchema>,
